const leadResult = $input.first().json;
const leads = Array.isArray(leadResult) ? leadResult : [leadResult];
const lead = leads[0];

if (!lead || !lead.id) {
  throw new Error('Lead not found');
}

// Dedup check
if (lead.salesperson_alerted === true) {
  return [{ json: { ...lead, _skip: true } }];
}

return [{ json: { ...lead, _skip: false } }];

const lead = $('Parse Lead + Dedup').first().json;
const messagesRaw = $input.first().json;
const messages = Array.isArray(messagesRaw) ? messagesRaw : [messagesRaw];

// Build formatted conversation log (oldest first)
const conversation = messages
  .filter(m => m && m.body)
  .reverse()
  .map(m => {
    const dir = m.direction === 'inbound' ? 'CUSTOMER' : 'AI';
    const time = m.sent_at ? new Date(m.sent_at).toLocaleString('en-CA', { timeZone: 'America/Toronto' }) : '';
    return `[${dir}] ${time}\n${m.body}`;
  })
  .join('\n\n');

const smsBody = `HOT LEAD: ${lead.first_name} ${lead.last_name || ''}\nPhone: ${lead.phone}\nVehicle: ${lead.vehicle_interest || 'Not specified'}\nIntent: ${lead.intent_score}\nCall them ASAP!`;

const emailSubject = `Hot Lead: ${lead.first_name} ${lead.last_name || ''} - ${lead.vehicle_interest || 'Vehicle Inquiry'}`;

const emailBody = `<div style="font-family: Arial, sans-serif; max-width: 600px;">
<h2 style="color: #dc2626;">Hot Lead Alert</h2>
<table style="border-collapse: collapse; width: 100%; margin-bottom: 20px;">
  <tr><td style="padding: 8px; border: 1px solid #e2e8f0; font-weight: bold;">Name</td><td style="padding: 8px; border: 1px solid #e2e8f0;">${lead.first_name} ${lead.last_name || ''}</td></tr>
  <tr><td style="padding: 8px; border: 1px solid #e2e8f0; font-weight: bold;">Phone</td><td style="padding: 8px; border: 1px solid #e2e8f0;"><a href="tel:${lead.phone}">${lead.phone}</a></td></tr>
  <tr><td style="padding: 8px; border: 1px solid #e2e8f0; font-weight: bold;">Email</td><td style="padding: 8px; border: 1px solid #e2e8f0;">${lead.email || 'N/A'}</td></tr>
  <tr><td style="padding: 8px; border: 1px solid #e2e8f0; font-weight: bold;">Source</td><td style="padding: 8px; border: 1px solid #e2e8f0;">${lead.source}</td></tr>
  <tr><td style="padding: 8px; border: 1px solid #e2e8f0; font-weight: bold;">Vehicle Interest</td><td style="padding: 8px; border: 1px solid #e2e8f0;">${lead.vehicle_interest || 'Not specified'}</td></tr>
  <tr><td style="padding: 8px; border: 1px solid #e2e8f0; font-weight: bold;">Intent Score</td><td style="padding: 8px; border: 1px solid #e2e8f0; color: #dc2626; font-weight: bold;">${(lead.intent_score || '').toUpperCase()}</td></tr>
</table>

<h3>Last 5 Messages</h3>
<div style="background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 8px; padding: 16px; font-size: 14px; white-space: pre-wrap;">${conversation || '(No messages yet)'}</div>

<p style="margin-top: 20px; color: #64748b; font-size: 12px;">This alert was sent by the DealerCRM automation system.</p>
</div>`;

return [{ json: {
  lead_id: lead.id,
  smsBody,
  emailSubject,
  emailBody
}}];
